import { Component, Element, Prop, Host, h } from '@stencil/core';
import { generateUniqueString } from '@src/utils/kds-utils/generateUniqueString';

/**
 * A vertical or horizontal menu bar that can be configured to contain a group of actionable buttons.
 * Used jointly with [kds-buttongroup-member](/stencil/mx-components/ButtongroupMember).
 */
@Component({
  tag: "kds-buttongroup",
  styleUrl: "kds-buttongroup.css",
  shadow: false
})
export class KdsButtonGroup {
  @Element() hostEl: HTMLKdsButtongroupElement;
  /** Displays toolbar horizontally if true */
  @Prop() readonly vertical: boolean = false;

  /** Sets type of button group. */
  @Prop() readonly groupType: "button" | "radio" | "checkbox" = "button";

  /** Sets radio group name to be used when groupType is "radio". Uniquely generated if not provided. */
  @Prop() readonly groupName?: string = generateUniqueString();

  // prettier-ignore
  @Prop() readonly palette: "neutral" | "brand" | "accent" | "positive" | "negative" | "informative" | "callout" | "special" = "brand";
  /** Sets the color kind. */
  @Prop() readonly kind: "dominant" | "prominent" | "subtle" | "alternate" = "prominent";
  /** Sets the color variant. */
  @Prop() readonly variant: "fill" | "border" | "minimal" = "fill";
  /** Applies the inverse color styling. */
  @Prop() readonly inverse: boolean = false;

  render() {
    return (
      <Host
        class={{
          "kds-ButtonGroup": true,
          "kds-ButtonGroup--horizontal": !this.vertical,
          "kds-ButtonGroup--vertical": this.vertical
        }}
        role='toolbar'
      >
        <slot />
      </Host>
    );
  }
}
